import ApiService, { ResponseType } from "@/api/api";
import { getTokenByBridge } from '@/utils';

// 以promsie的形式获取 userInfo
export function getUserInfo(): any {
  return new Promise((resolve) => {
    const t = Date.now()
    window.ConnectWebViewBridgeSDK.getUserInfo((data: Record<string, any>) => {
      console.log("sdk callback", Date.now() - t)
      resolve(data);
    });
    // 兜底SDK没有回调的情况
    setTimeout(() => {
      resolve({ token: "", stu_talid: "" })
    }, 10000)
  });
}

export const getPlanDetail = async (params: {
  tal_id: string;
  group_id: string;
  group_type: number;
}) => {
  const token = await getTokenByBridge();
  return ApiService.post("/parent/api/v1/study-schedule/detail", {
    ...params,
    token,
  });
};

export const getCustomTaskList = async (data: any) => {
  const { stu_talid, token } = await getUserInfo();
  return ApiService.post("/stu-parent/schedule/v1/custom-task/list", {
    ...data,
    stu_tal_id: stu_talid,
    token,
  });
};
