import dayjs from "dayjs";
export const timeFormat = (time: number, type = "YMD") => {
  const date = new Date(time);
  const year = date.getFullYear();
  const month = date.getMonth() + 1;
  const day = date.getDate();
  const dayOfWeek = date.getDay();

  switch (type) {
    case "YMD":
      return `${year}年${month}月${day}日`;
    case "YM":
      return `${year}年${month}月`;
    case "MD":
      return `${month}月${day}日`;
    case "MDW":
      return `${month}月${day}日 周${dayOfWeek}`;
    default:
      return "";
      break;
  }
};

export const toListGroup = (list: any) => {
  const res = [];

  for (const i of list) {
    const groupIndex = res.findIndex((item) => {
      return item.groupName === i.schedule_date;
    });
    if (groupIndex > -1) {
      res[groupIndex].groups.push(i);
    } else {
      res.push({
        groupName: i.schedule_date,
        groups: [i],
      });
    }
  }
  return res;
};

export const formatDate = (date: any) => {
  const d = dayjs(date);
  const today = dayjs();
  if (today.isSame(d, "day")) {
    return "今天";
  } else if (today.isSame(d, "year")) {
    return d.format("M[月]D[日]");
  } else {
    return d.format("YYYY[年]M[月]D[日]");
  }
};
